import{_ as n,o as s,c as a,ae as t}from"./chunks/framework.6gkcVjOI.js";const m=JSON.parse('{"title":"Agent Loop Deep Dive","description":"The state machine nature of the agent loop — stop_reason transitions, history management, and the permission gate","frontmatter":{"title":"Agent Loop Deep Dive","description":"The state machine nature of the agent loop — stop_reason transitions, history management, and the permission gate"},"headers":[],"relativePath":"architecture/agent-loop.md","filePath":"architecture/agent-loop.md","lastUpdated":1775210533000}'),i={name:"architecture/agent-loop.md"};function r(o,e,l,p,c,h){return s(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="agent-loop-deep-dive" tabindex="-1">Agent Loop Deep Dive <a class="header-anchor" href="#agent-loop-deep-dive" aria-label="Permalink to &quot;Agent Loop Deep Dive&quot;">​</a></h1><p>The agent loop is the heart of go-code&#39;s execution engine. But describing it as a &quot;loop&quot; obscures its true nature: it is a <strong>state machine</strong> where each iteration represents a transition between well-defined states, governed by the model&#39;s response through the <code>stop_reason</code> mechanism.</p><p>Understanding the agent loop as a state machine — rather than a simple iteration — reveals why certain design decisions were made and how they contribute to reliability.</p><h2 id="the-state-machine-view" tabindex="-1">The State Machine View <a class="header-anchor" href="#the-state-machine-view" aria-label="Permalink to &quot;The State Machine View&quot;">​</a></h2><p>At any point in execution, the agent is in one of a defined set of states. The transitions between these states are determined by the model&#39;s response:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                        Agent State Machine                                  │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                                                                              │</span></span>
<span class="line"><span>│         ┌──────────────────────────────────────────────────────────────┐   │</span></span>
<span class="line"><span>│         │                                                              │   │</span></span>
<span class="line"><span>│         │    ┌─────────┐    ┌─────────┐    ┌─────────┐    ┌───────┐ │   │</span></span>
<span class="line"><span>│         │    │ REQUEST │───▶│ WAITING │───▶│ RESPONSE│───▶│DECISION│ │   │</span></span>
<span class="line"><span>│         │    │  STATE  │    │  STATE  │    │  STATE  │    │ STATE  │ │   │</span></span>
<span class="line"><span>│         │    └─────────┘    └─────────┘    └─────────┘    └────┬────┘ │   │</span></span>
<span class="line"><span>│         │         ▲              │              │               │      │   │</span></span>
<span class="line"><span>│         │         │              │              │               │      │   │</span></span>
<span class="line"><span>│         │         └──────────────┴──────────────┴───────────────┘      │   │</span></span>
<span class="line"><span>│         │                              │                                  │   │</span></span>
<span class="line"><span>│         │                              │                                  │   │</span></span>
<span class="line"><span>│         │              ┌───────────────┴───────────────┐                 │   │</span></span>
<span class="line"><span>│         │              │                               │                 │   │</span></span>
<span class="line"><span>│         │              ▼                               ▼                 │   │</span></span>
<span class="line"><span>│         │    ┌─────────────────┐           ┌─────────────────────────┐     │   │</span></span>
<span class="line"><span>│         │    │  end_turn       │           │  tool_use               │     │   │</span></span>
<span class="line"><span>│         │    │  (TERMINAL)    │           │  (CONTINUE)             │     │   │</span></span>
<span class="line"><span>│         │    │                 │           │                         │     │   │</span></span>
<span class="line"><span>│         │    │ Return result  │           │  1. Permission check   │     │   │</span></span>
<span class="line"><span>│         │    │ to user        │           │  2. Tool execution     │     │   │</span></span>
<span class="line"><span>│         │    └─────────────────┘           │  3. Add results to     │     │   │</span></span>
<span class="line"><span>│         │                                    │  history              │     │   │</span></span>
<span class="line"><span>│         │                                    │  4. Transition back   │     │   │</span></span>
<span class="line"><span>│         │                                    │  to REQUEST state     │     │   │</span></span>
<span class="line"><span>│         │                                    └─────────────────────────┘     │   │</span></span>
<span class="line"><span>│         │                                                              │      │   │</span></span>
<span class="line"><span>│         └──────────────────────────────────────────────────────────────┘      │   │</span></span>
<span class="line"><span>│                                                                              │</span></span>
<span class="line"><span>│    Error Transitions:                                                       │</span></span>
<span class="line"><span>│    ┌──────────────────────────────────────────────────────────────────┐     │</span></span>
<span class="line"><span>│    │  max_tokens ──▶ Return truncated response with warning          │     │</span></span>
<span class="line"><span>│    │  max_turns  ──▶ Return with loop termination warning            │     │</span></span>
<span class="line"><span>│    │  error      ──▶ Return error to user                             │     │</span></span>
<span class="line"><span>│    └──────────────────────────────────────────────────────────────────┘     │</span></span>
<span class="line"><span>│                                                                              │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br></div></div><h2 id="stop-reason-as-state-transition" tabindex="-1">Stop Reason as State Transition <a class="header-anchor" href="#stop-reason-as-state-transition" aria-label="Permalink to &quot;Stop Reason as State Transition&quot;">​</a></h2><p>The <code>stop_reason</code> field in the API response is not merely a status code — it is the <strong>state transition signal</strong> that determines the agent&#39;s next action. Each possible value represents a different state transition:</p><h3 id="end-turn-terminal-state" tabindex="-1">end_turn: Terminal State <a class="header-anchor" href="#end-turn-terminal-state" aria-label="Permalink to &quot;end_turn: Terminal State&quot;">​</a></h3><p>When <code>stop_reason</code> is <code>end_turn</code> (or <code>stop_sequence</code>), the model has completed its task. The response contains the final message to the user, and the agent loop terminates. This is a <strong>terminal state</strong> — no further transitions occur.</p><p>This state represents the model&#39;s confidence that the user&#39;s request has been fulfilled. The harness does not second-guess this decision — it trusts the model&#39;s assessment and returns the result.</p><h3 id="tool-use-continue-state" tabindex="-1">tool_use: Continue State <a class="header-anchor" href="#tool-use-continue-state" aria-label="Permalink to &quot;tool_use: Continue State&quot;">​</a></h3><p>When <code>stop_reason</code> is <code>tool_use</code>, the model has requested to execute one or more tools to gather additional information or perform actions. The agent transitions to tool execution:</p><ol><li><p><strong>Permission Gate</strong>: Each requested tool passes through the permission system. If any tool is denied, its result is an error, but the loop continues.</p></li><li><p><strong>Parallel Execution</strong>: Multiple tool requests are executed in parallel. The model can request several operations simultaneously, and the harness coordinates their execution.</p></li><li><p><strong>Result Capture</strong>: Tool results (or errors) are captured and added to the conversation history.</p></li><li><p><strong>State Transition</strong>: After tool execution, the agent transitions back to the REQUEST state, where the updated history is used to build the next API request.</p></li></ol><h3 id="max-tokens-truncation-state" tabindex="-1">max_tokens: Truncation State <a class="header-anchor" href="#max-tokens-truncation-state" aria-label="Permalink to &quot;max_tokens: Truncation State&quot;">​</a></h3><p>When <code>stop_reason</code> is <code>max_tokens</code>, the response was truncated because the maximum token limit was reached. This is not a failure — it&#39;s a boundary condition. The harness returns the partial response with a warning, allowing the user to decide whether to continue.</p><h3 id="max-turns-loop-limit-state" tabindex="-1">max_turns: Loop Limit State <a class="header-anchor" href="#max-turns-loop-limit-state" aria-label="Permalink to &quot;max_turns: Loop Limit State&quot;">​</a></h3><p>When the agent reaches the maximum number of iterations (MAX_TURNS = 50) without completing, it terminates with a warning. This is a <strong>safety bound</strong> — see the next section for why this exists.</p><h2 id="why-max-turns-exists" tabindex="-1">Why MAX_TURNS Exists <a class="header-anchor" href="#why-max-turns-exists" aria-label="Permalink to &quot;Why MAX_TURNS Exists&quot;">​</a></h2><p>The model has no intrinsic understanding of time, resource constraints, or iteration counts. Left to run indefinitely, an agent could:</p><ul><li>Call the same tool repeatedly in an infinite loop</li><li>Oscillate between ineffective strategies</li><li>Consume unbounded computational resources</li></ul><p>MAX_TURNS provides a <strong>hard safety bound</strong>. At 50 iterations, even a misbehaving agent will terminate. This number was chosen based on empirical observation: complex tasks rarely require more than 50 tool invocations, while simpler tasks complete well before this limit.</p><p>The value is configurable, allowing users who need more iterations to increase the limit while still maintaining <em>some</em> bound on execution time.</p><h3 id="what-happens-at-max-turns" tabindex="-1">What Happens at MAX_TURNS <a class="header-anchor" href="#what-happens-at-max-turns" aria-label="Permalink to &quot;What Happens at MAX_TURNS&quot;">​</a></h3><p>When the limit is reached, the agent:</p><ol><li>Stops making new API requests</li><li>Returns the accumulated response to the user</li><li>Includes a warning message indicating the loop was terminated</li></ol><p>The user can then decide whether to continue the task manually or adjust the MAX_TURNS setting.</p><h2 id="history-management-for-long-conversations" tabindex="-1">History Management for Long Conversations <a class="header-anchor" href="#history-management-for-long-conversations" aria-label="Permalink to &quot;History Management for Long Conversations&quot;">​</a></h2><p>The conversation history is not merely a log — it is the <strong>context</strong> that allows the model to understand the ongoing task. Managing this history is one of the harness&#39;s most critical responsibilities.</p><h3 id="the-token-budget-problem" tabindex="-1">The Token Budget Problem <a class="header-anchor" href="#the-token-budget-problem" aria-label="Permalink to &quot;The Token Budget Problem&quot;">​</a></h3><p>Every message in the history consumes tokens from the model&#39;s context window. A 50-turn conversation with 6 tool calls per turn could easily exceed 100,000 tokens — more than most models support.</p><p>Without management, the agent would either:</p><ul><li>Fail when hitting the token limit</li><li>Truncate critical context needed for the task</li></ul><h3 id="three-tier-compaction" tabindex="-1">Three-Tier Compaction <a class="header-anchor" href="#three-tier-compaction" aria-label="Permalink to &quot;Three-Tier Compaction&quot;">​</a></h3><p>go-code implements a three-tier approach to history management:</p><p><strong>Tier 1: Full Retention</strong> — Early messages in the conversation are retained in full. These establish the task context and initial reasoning.</p><p><strong>Tier 2: Selective Compression</strong> — Messages from the middle of the conversation are compressed into summaries that preserve key information (tool calls, their results, important decisions) while removing verbose details.</p><p><strong>Tier 3: Pruning</strong> — If the conversation exceeds a certain length, older messages are pruned entirely, keeping only the most recent context.</p><p>This tiered approach ensures the model always has access to:</p><ul><li>The original task description</li><li>Recent tool executions and their results</li><li>The current state of work</li></ul><p>While discarding information that is no longer relevant to the task at hand.</p><h3 id="why-compaction-matters" tabindex="-1">Why Compaction Matters <a class="header-anchor" href="#why-compaction-matters" aria-label="Permalink to &quot;Why Compaction Matters&quot;">​</a></h3><p>Without compaction, the system would be limited to approximately 8-10 tool invocations before hitting token limits. With compaction, conversations can span 50+ iterations while maintaining enough context for the model to complete complex tasks.</p><p>Compaction is lossy — some information is inevitably discarded. But this is a necessary trade-off. The alternative (no compaction, limited conversation length) would be far more restrictive.</p><h2 id="the-permission-gate-as-safety-checkpoint" tabindex="-1">The Permission Gate as Safety Checkpoint <a class="header-anchor" href="#the-permission-gate-as-safety-checkpoint" aria-label="Permalink to &quot;The Permission Gate as Safety Checkpoint&quot;">​</a></h2><p>Every tool execution passes through the permission system before execution. This is not optional — it is a <strong>mandatory checkpoint</strong> that guards dangerous operations.</p><h3 id="why-a-gate-not-a-filter" tabindex="-1">Why a Gate, Not a Filter <a class="header-anchor" href="#why-a-gate-not-a-filter" aria-label="Permalink to &quot;Why a Gate, Not a Filter&quot;">​</a></h3><p>A filter would allow dangerous operations to pass through, relying on the model to avoid them. A gate actively intercepts and blocks operations that don&#39;t meet the configured policy.</p><p>This distinction is critical because the model operates with the user&#39;s full privileges. Without a gate, a misbehaving model could:</p><ul><li>Delete all files in the user&#39;s directory</li><li>Execute malicious shell commands</li><li>Exfiltrate sensitive data</li></ul><h3 id="the-gate-architecture" tabindex="-1">The Gate Architecture <a class="header-anchor" href="#the-gate-architecture" aria-label="Permalink to &quot;The Gate Architecture&quot;">​</a></h3><p>The permission gate operates at the tool call level:</p><ol><li><p><strong>Tier Check</strong>: The requested tool is evaluated against the user&#39;s permission tier (ReadOnly, WorkspaceWrite, DangerFullAccess).</p></li><li><p><strong>Path Matching</strong>: For file operations, glob patterns determine whether the specific path is allowed.</p></li><li><p><strong>Operation Evaluation</strong>: Some operations (like deletion) are treated as inherently dangerous and may require additional approval.</p></li><li><p><strong>User Prompt</strong>: If human-in-the-loop mode is enabled and the operation requires approval, the user is prompted before execution proceeds.</p></li><li><p><strong>Decision Enforcement</strong>: The gate returns either approval or denial. If denied, the tool is not executed, and an error result is returned to the model.</p></li></ol><h3 id="what-the-model-sees" tabindex="-1">What the Model Sees <a class="header-anchor" href="#what-the-model-sees" aria-label="Permalink to &quot;What the Model Sees&quot;">​</a></h3><p>The model doesn&#39;t see the permission gate — it only sees tool results. If a tool is denied, the model receives an error result indicating the operation was blocked. The model must then decide how to proceed: try a different approach, request permission, or report the issue to the user.</p><h2 id="streaming-and-real-time-feedback" tabindex="-1">Streaming and Real-Time Feedback <a class="header-anchor" href="#streaming-and-real-time-feedback" aria-label="Permalink to &quot;Streaming and Real-Time Feedback&quot;">​</a></h2><p>The agent loop supports streaming output, allowing the user to see the model&#39;s response as it&#39;s generated. This is not merely a UX feature — it provides <strong>early indication of progress</strong>.</p><h3 id="why-streaming-matters" tabindex="-1">Why Streaming Matters <a class="header-anchor" href="#why-streaming-matters" aria-label="Permalink to &quot;Why Streaming Matters&quot;">​</a></h3><p>Without streaming, the user would wait in silence until the complete response arrives — potentially many seconds for long outputs. With streaming, the user can:</p><ul><li>See that the request was received and is being processed</li><li>Observe partial progress on long responses</li><li>Interrupt the operation if something appears wrong</li></ul><h3 id="how-streaming-works" tabindex="-1">How Streaming Works <a class="header-anchor" href="#how-streaming-works" aria-label="Permalink to &quot;How Streaming Works&quot;">​</a></h3><p>The API client receives tokens incrementally and invokes a callback for each token delta. The harness uses this callback to:</p><ul><li>Stream text output to the terminal</li><li>Display progress indicators during tool execution</li><li>Provide real-time feedback to the user</li></ul><p>The loop itself continues to process the full response — streaming is purely a display optimization.</p><h2 id="execution-flow-in-state-machine-terms" tabindex="-1">Execution Flow in State Machine Terms <a class="header-anchor" href="#execution-flow-in-state-machine-terms" aria-label="Permalink to &quot;Execution Flow in State Machine Terms&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. INITIALIZE</span></span>
<span class="line"><span>   - Create new session history</span></span>
<span class="line"><span>   - Add user message to history</span></span>
<span class="line"><span>   - Transition to: REQUEST</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. REQUEST</span></span>
<span class="line"><span>   - Apply compaction if needed</span></span>
<span class="line"><span>   - Build API request (messages + tools)</span></span>
<span class="line"><span>   - Send request to API</span></span>
<span class="line"><span>   - Transition to: WAITING</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. WAITING</span></span>
<span class="line"><span>   - Receive streaming response</span></span>
<span class="line"><span>   - Buffer complete response</span></span>
<span class="line"><span>   - Transition to: RESPONSE</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. RESPONSE</span></span>
<span class="line"><span>   - Parse stop_reason</span></span>
<span class="line"><span>   - Extract content blocks</span></span>
<span class="line"><span>   - Transition to: DECISION</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. DECISION (state branching)</span></span>
<span class="line"><span>   - end_turn    → TERMINATE</span></span>
<span class="line"><span>   - tool_use    → TOOL_EXECUTION</span></span>
<span class="line"><span>   - max_tokens  → TERMINATE (with warning)</span></span>
<span class="line"><span>   - max_turns   → TERMINATE (with warning)</span></span>
<span class="line"><span>   - error       → TERMINATE (with error)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. TOOL_EXECUTION</span></span>
<span class="line"><span>   - For each tool_use block:</span></span>
<span class="line"><span>     a. Permission gate check</span></span>
<span class="line"><span>     b. Execute tool (with timeout)</span></span>
<span class="line"><span>     c. Capture result (or error)</span></span>
<span class="line"><span>   - Add all results to history</span></span>
<span class="line"><span>   - Transition to: REQUEST</span></span>
<span class="line"><span></span></span>
<span class="line"><span>7. TERMINATE</span></span>
<span class="line"><span>   - Format final response</span></span>
<span class="line"><span>   - Return to user</span></span>
<span class="line"><span>   - End of execution</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br></div></div><h2 id="related-documentation" tabindex="-1">Related Documentation <a class="header-anchor" href="#related-documentation" aria-label="Permalink to &quot;Related Documentation&quot;">​</a></h2><ul><li><a href="./overview.html">Architecture Overview</a> — System components and data flow</li><li><a href="./design-philosophy.html">Design Philosophy</a> — Intelligence/reliability separation</li><li><a href="./tools.html">Tool System</a> — Tool implementations and permission configuration</li></ul>`,68)])])}const d=n(i,[["render",r]]);export{m as __pageData,d as default};
